from bs4 import BeautifulSoup
from typing import List, Dict
#  弃用：结构提取混乱
def parse_building_code_table(html_table_str: str) -> str:
    """
    专门适配《建筑设计防火规范》等工程规范表格的HTML→Markdown转换器
    完美处理多级表头、合并单元格、大类-子构件嵌套结构
    输入：MinerU提取的带合并单元格的HTML表格
    输出：标准、扁平、LLM友好的Markdown表格
    """
    try:
        soup = BeautifulSoup(html_table_str, "html.parser")
        table = soup.find("table")
        if not table:
            return "错误：未找到表格"

        rows = table.find_all("tr")
        if len(rows) < 2:
            return "错误：表格行数不足"

        # ================== 1. 解析表头（处理多级表头、合并单元格） ==================
        # 第一行：构件名称 + 耐火等级（跨列）
        header_row1 = rows[0].find_all(["td", "th"])
        # 第二行：一级/二级/三级/四级
        header_row2 = rows[1].find_all(["td", "th"])

        # 自动补全表头，生成标准列名
        col_names = ["构件大类", "构件名称"]
        for h in header_row2[1:]:  # 跳过第一列（空/构件名称）
            col_name = h.get_text(strip=True)
            if col_name:
                col_names.append(col_name)

        # ================== 2. 解析数据行（处理大类合并单元格） ==================
        data_rows: List[Dict[str, str]] = []
        current_category = ""  # 记录当前大类（如墙/柱/梁）

        for row in rows[2:]:  # 从第三行开始是数据
            cells = row.find_all(["td", "th"])
            cell_texts = [c.get_text(strip=True).replace("\n", "") for c in cells]

            # 处理大类合并单元格：第一列有值则更新current_category，否则沿用
            if cell_texts[0]:
                current_category = cell_texts[0]

            # 提取子构件名称 + 各耐火等级数据
            row_data = {
                "构件大类": current_category,
                "构件名称": cell_texts[1] if len(cell_texts) > 1 else current_category
            }
            # 填充一级/二级/三级/四级数据
            for i, col in enumerate(col_names[2:], start=2):
                row_data[col] = cell_texts[i] if i < len(cell_texts) else ""

            data_rows.append(row_data)

        # ================== 3. 生成标准Markdown表格 ==================
        md_lines = []
        # 表头
        header_line = "|" + "|".join([f" {col} " for col in col_names]) + "|"
        md_lines.append(header_line)
        # 分隔线
        split_line = "|" + "|".join(["---" for _ in col_names]) + "|"
        md_lines.append(split_line)
        # 数据行
        for row in data_rows:
            line = "|"
            for col in col_names:
                line += f" {row[col]} |"
            md_lines.append(line)

        return "\n".join(md_lines)

    except Exception as e:
        return f"表格解析失败：{str(e)}"


